async (page) => {
  // Walk adjacent to Forester at (216, 114) — try (215, 114)
  await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 215, y: 114});
  await page.waitForTimeout(3000);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const forester = gs.nearby_entities.find(e => e.name === 'Forester');
    return JSON.stringify({
      pos: gs.player_position,
      forester: forester ? {id: forester.id, dist: forester.distance} : null
    });
  });
  return state;
}

async (page) => {
  // Set attack style to Hack, re-install screenshot hook
  await page.evaluate(() => {
    window.game.player.setAttackStyle(0);
    if (!window.__liveScreenshotActive) {
      window.__liveScreenshotActive = true;
      setInterval(() => console.log('LIVE_SCREENSHOT_TRIGGER'), 1000);
    }
  });

  const asciiMap = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    return m && !m.error ? (m.ascii + '\n\n' + m.legendText) : 'no map';
  });
  return 'Attack style set. ASCII_MAP:\n' + asciiMap;
}

