async (page) => {
  // Click RESPAWN button
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: x, clientY: y, bubbles: true, ctrlKey: false}));
  }, {x: 640, y: 364});
  await page.waitForTimeout(3000);

  // Warp to Mudwich
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);

  // Re-equip bronze axe and set attack style
  await page.evaluate(() => window.game.player.setAttackStyle(0));
  await page.waitForTimeout(500);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const logs = gs.inventory.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0);
    return JSON.stringify({ pos: gs.player_position, stats: gs.player_stats, logs, inventory: gs.inventory });
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return state;
}

async (page) => {
  // Find and click the respawn button by text content
  await page.evaluate(() => {
    // Try multiple methods to find respawn button
    const allBtns = document.querySelectorAll('button, .button, input[type=button]');
    for (const btn of allBtns) {
      if (btn.textContent.includes('RESPAWN') || btn.value?.includes('RESPAWN')) {
        btn.click();
        return 'clicked: ' + btn.textContent;
      }
    }
    // Try by class name patterns
    const respawnBtn = document.querySelector('#respawn, .respawn, [id*="respawn"]');
    if (respawnBtn) { respawnBtn.click(); return 'clicked by id'; }
    return 'no respawn button found';
  });
  await page.waitForTimeout(3000);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({ pos: gs.player_position, hp: gs.player_stats.hp, max_hp: gs.player_stats.max_hp });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return state;
}
